import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Task } from '../../models/task.model';
import { TaskFormComponent } from '../task-form/task-form.component';
import { TaskService } from '../../services/task.service'; 

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [CommonModule, TaskFormComponent],
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.css']
})
export class TaskListComponent implements OnInit {
  tasks: Task[] = [];

  private taskService = inject(TaskService);

  ngOnInit() {
    this.loadTasks();
  }

  loadTasks() {
    this.taskService.getTasks().subscribe({
      next: (data) => {
        this.tasks = data;
      },
      error: (err) => console.error('Error al cargar la base de datos', err)
    });
  }

  getTasksByStatus(status: 'pending' | 'in-progress' | 'completed' | 'on-review' | 'blocked'): Task[] {
    return this.tasks.filter(task => task.status === status);
  }

  changeStatus(task: Task, newStatus: 'pending' | 'in-progress' | 'completed' | 'on-review' | 'blocked') {
    if (!task.id) return;

    const oldStatus = task.status;
    task.status = newStatus;

    this.taskService.updateTask(task.id, { status: newStatus }).subscribe({
      error: (err) => {
        console.error('Error al actualizar', err);
        task.status = oldStatus;
      }
    });
  }

  deleteTask(id: string | undefined) {
    if (!id) return;

    this.taskService.deleteTask(id).subscribe({
      next: () => {
        this.tasks = this.tasks.filter(task => task.id !== id);
      },
      error: (err) => console.error('Error al eliminar', err)
    });
  }

  onTaskAdded(newTask: Task) {
    this.taskService.createTask(newTask).subscribe({
      next: (createdTask) => {
        this.tasks.unshift(createdTask);
      },
      error: (err) => console.error('Error al crear', err)
    });
  }
}
